import { extractUniqueIndicatorsByPriority } from './extract-unique-indicators-by-priority.js';
import { filterIndicatorsOutOfBounds } from './filter-indicators-out-of-bounds.js';
import { IndicatorData } from '../types.js';

/**
 * Filters out indicators that are outside the provided domain and returns unique indicators by priority for each track.
 * @param indicators - A 2D array of IndicatorData, where each sub-array represents a track of indicators.
 * @param domain - The start and end of the domain [domainStart, domainEnd].
 * @returns An array of tracks, where each track contains `[key, IndicatorData]` tuples of unique indicators filtered by priority and domain bounds.
 * @internal
 */
export const getUniqueIndicatorsByPriority = (
  indicators: IndicatorData[][],
  [domainStart, domainEnd]: number[],
): [string, IndicatorData][][] => {
  const filteredIndicators = filterIndicatorsOutOfBounds(indicators, [
    domainStart,
    domainEnd,
  ]);
  return extractUniqueIndicatorsByPriority(filteredIndicators);
};
